# --- Sensitive Data Filter ---

class SensitiveDataFilter(logging.Filter):
    """Filter that redacts sensitive information from log records."""

    SENSITIVE_FIELDS = {
        'password', 'passwd', 'pwd', 'secret', 'token', 'access_token',
        'refresh_token', 'api_key', 'apikey', 'authorization', 'auth_token',
        'session_id', 'sessionid', 'credit_card', 'card_number', 'cvv',
        'ssn', 'social_security', 'private_key', 'client_secret',
    }

    SENSITIVE_PATTERNS = [
        (re.compile(r'(Bearer\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(Basic\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'("(?:password|token|secret|api_key|authorization|auth_token)":\s*")[^"]*(")', re.IGNORECASE),
         r'\1[REDACTED]\2'),
        (re.compile(r'((?:password|token|secret|api_key)=)[^&\s]+', re.IGNORECASE), r'\1[REDACTED]'),
    ]

    def filter(self, record):
        if isinstance(record.msg, str):
            record.msg = self._redact_string(record.msg)
        if record.args:
            record.args = self._redact_args(record.args)
        return True

    def _redact_string(self, text):
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            text = pattern.sub(replacement, text)
        return text

    def _redact_args(self, args):
        if isinstance(args, dict):
            return {k: self._redact_value(k, v) for k, v in args.items()}
        elif isinstance(args, (list, tuple)):
            redacted = []
            for arg in args:
                if isinstance(arg, str):
                    redacted.append(self._redact_string(arg))
                else:
                    redacted.append(arg)
            return tuple(redacted)
        return args

    def _redact_value(self, key, value):
        if isinstance(key, str) and key.lower() in self.SENSITIVE_FIELDS:
            return '[REDACTED]'
        if isinstance(value, str):
            return self._redact_string(value)
        if isinstance(value, dict):
            return {k: self._redact_value(k, v) for k, v in value.items()}
        return value


