def require_auth(f):
    """Authentication decorator with security logging."""
    @wraps(f)
    def decorated(*args, **kwargs):
        security_logger = logging.getLogger('security')

        auth_header = request.headers.get('Authorization')
        if not auth_header:
            security_logger.warning(
                "AUTH_MISSING | Path: %s | IP: %s",
                request.path, request.remote_addr
            )
            return jsonify({'error': 'Authorization header required'}), 401

        # Log that auth was provided (but NOT the token value)
        security_logger.info(
            "AUTH_ATTEMPT | Path: %s | IP: %s | Auth-Type: %s",
            request.path, request.remote_addr,
            auth_header.split()[0] if ' ' in auth_header else 'unknown'
        )

        # Simple token validation (replace with real validation)
        if auth_header == 'Bearer valid-token-123':
            g.user_id = 'authenticated_user'
            security_logger.info(
                "AUTH_SUCCESS | User: %s | Path: %s | IP: %s",
                g.user_id, request.path, request.remote_addr
            )
            return f(*args, **kwargs)
        else:
            security_logger.warning(
                "AUTH_FAILED | Path: %s | IP: %s | Reason: invalid_token",
                request.path, request.remote_addr
                # NOTE: We do NOT log the actual token value
            )
            return jsonify({'error': 'Invalid authentication token'}), 401

    return decorated


